def get_disease_text(result, T, lang):
    is_hi = "Hindi" in lang or lang in ["हिंदी (Hindi)", "भोजपुरी (Bhojpuri)", "राजस्थानी (Rajasthani)",
             "हरियाणवी (Haryanvi)", "छत्तीसगढ़ी (Chhattisgarhi)", "बुंदेली (Bundeli)",
             "अवधी (Awadhi)", "मगही (Magahi)", "ब्रजभाषा (Brajbhasha)", "मारवाड़ी (Marwari)",
             "कुमाऊँनी (Kumaoni)", "गढ़वाली (Garhwali)", "मीणा (Meena)","शेखावाटी (Shekhawati)",
             "वागड़ी (Vagdi)","मैथिली (Maithili)","डोगरी (Dogri)","संस्कृत (Sanskrit)","नेपाली (Nepali)"]
    if is_hi:
        return result["cause_hi"], result["treat_hi"], result["prev_hi"], result["sev_hi"]
    return result["cause_en"], result["treat_en"], result["prev_en"], result["sev_en"]

# ── MAIN APP ─────────────────────────────────────────────────
# Language selector — FIRST
lang = st.selectbox(
    "🌍 अपनी भाषा चुनें / Select Language / ਭਾਸ਼ਾ ਚੁਣੋ / ഭാഷ / மொழி / భాష",
    list(LANGUAGES.keys()),
    index=0
)

T = LANGUAGES[lang]

# Badge
badge = T.get("badge", "🌾 Regional")
cols = st.columns([3, 1])
with cols[0]:
    st.title(T["t"])
with cols[1]:
    st.markdown(f"<br><span style='background:#e8f5e9;padding:4px 10px;border-radius:12px;font-size:13px;'>{badge}</span>", unsafe_allow_html=True)

st.divider()

# Upload
uploaded = st.file_uploader(T["u"], type=["jpg", "jpeg", "png", "webp"])

if uploaded:
    img = Image.open(uploaded)
    st.image(img, use_column_width=True)
    st.divider()

    with st.spinner(T["a"]):
        bar = st.progress(0)
        for i in range(100):
            time.sleep(0.013)
            bar.progress(i + 1)

    result = random.choices(DISEASES, weights=[0.22, 0.20, 0.18, 0.15, 0.10, 0.15])[0]
    cause, treat, prev, sev = get_disease_text(result, T, lang)

    c1, c2, c3 = st.columns(3)
    nm = result["name"].split("/")[0].strip()
    c1.metric(T["dl"], nm[:16] + "..." if len(nm) > 16 else nm)
    c2.metric(T["cl"], result["conf"])
    c3.metric(T["sl"], sev)

    st.divider()

    col1, col2 = st.columns(2)
    with col1:
        fn = st.success if result["ok"] else st.error
        fn(f"**{result['name'].split('/')[0].strip()}**\n\n**{T['ca']}:** {cause}")
    with col2:
        st.warning(f"{T['tr']}\n\n{treat}")
        st.info(f"{T['pr']}\n\n{prev}")

    st.divider()
    st.subheader(T["st"])
    if result["ok"]:
        st.success(T["h"])
    else:
        for i, s in enumerate(T["s"], 1):
            st.write(f"{i}. {s}")

    if st.button(T["r"]):
        st.rerun()

else:
    c1, c2, c3, c4 = st.columns(4)
    c1.metric("🌾", "100+", "Crops")
    c2.metric("🦠", "500+", "Diseases")
    c3.metric("🌍", "50+", "Languages")
    c4.metric("🎯", "95%+", "Accuracy")
    st.divider()
    st.info("👆 " + T["u"])

st.divider()
st.caption("🌿 Kisan AI — Plant Doctor | Bhagwati Ahirwar | B.Tech AI & DS | CGPA 8.29")
st.caption("Supports 50+ Indian Languages — 22 Official + 28 Regional Dialects 🇮🇳")